use crate::usize::tests::{
    set::test_support::build,
    test_support::{MID_VALUE, build_from_vec, interval_pair, iv},
};

#[test]
fn search_point_returns_none_on_empty_set() {
    let set = build([]);

    assert_eq!(set.interval_containing_point(usize::MIN), None);
    assert_eq!(set.interval_containing_point(MID_VALUE), None);
    assert_eq!(set.interval_containing_point(usize::MAX), None);
}

#[test]
fn search_point_respects_half_open_bounds() {
    let set = build([(10, 20)]);

    assert_eq!(set.interval_containing_point(9), None);
    assert_eq!(set.interval_containing_point(10), Some(iv(10, 20)));
    assert_eq!(set.interval_containing_point(19), Some(iv(10, 20)));
    assert_eq!(set.interval_containing_point(20), None);
}

#[test]
fn search_point_returns_matching_interval_across_multiple_intervals() {
    let set = build([(10, 20), (30, 40), (50, 60)]);

    assert_eq!(set.interval_containing_point(10), Some(iv(10, 20)));
    assert_eq!(set.interval_containing_point(35), Some(iv(30, 40)));
    assert_eq!(set.interval_containing_point(59), Some(iv(50, 60)));

    assert_eq!(set.interval_containing_point(0), None);
    assert_eq!(set.interval_containing_point(20), None);
    assert_eq!(set.interval_containing_point(45), None);
    assert_eq!(set.interval_containing_point(usize::MAX), None);
}

#[test]
fn search_point_returns_merged_interval_after_canonicalization() {
    let set = build([(0, 5), (5, 10), (12, 20), (18, 30)]);

    assert_eq!(set.as_slice(), &[iv(0, 10), iv(12, 30)]);

    assert_eq!(set.interval_containing_point(0), Some(iv(0, 10)));
    assert_eq!(set.interval_containing_point(9), Some(iv(0, 10)));
    assert_eq!(set.interval_containing_point(10), None);
    assert_eq!(set.interval_containing_point(11), None);
    assert_eq!(set.interval_containing_point(12), Some(iv(12, 30)));
    assert_eq!(set.interval_containing_point(29), Some(iv(12, 30)));
    assert_eq!(set.interval_containing_point(30), None);
}

#[test]
fn search_point_handles_domain_edges() {
    let set = build([(usize::MIN, usize::MIN + 1), (usize::MAX - 1, usize::MAX)]);

    assert_eq!(
        set.interval_containing_point(usize::MIN),
        Some(iv(usize::MIN, usize::MIN + 1))
    );
    assert_eq!(set.interval_containing_point(usize::MIN + 1), None);

    assert_eq!(
        set.interval_containing_point(usize::MAX - 1),
        Some(iv(usize::MAX - 1, usize::MAX))
    );
    assert_eq!(set.interval_containing_point(usize::MAX), None);
}

#[test]
fn search_point_matches_contains_point_predicate() {
    let set = build([(10, 20), (30, 40), (50, 60)]);

    for x in [usize::MIN, 9, 10, 19, 20, 30, 39, 40, 55, 60, usize::MAX] {
        assert_eq!(
            set.interval_containing_point(x).is_some(),
            set.contains_point(x),
            "point = {x}"
        );
    }
}

